import React, { useState } from "react";

function SubscriptionForm({ subscriptions, setSubscriptions }) {
  const [name, setName] = useState("");
  const [amount, setAmount] = useState("");

  const addSubscription = () => {
    const trimmedName = name.trim();
    const parsedAmount = parseFloat(amount);

    if (!trimmedName || isNaN(parsedAmount) || parsedAmount <= 0) {
      alert("Enter a valid subscription name and a positive amount");
      return;
    }

  const deleteSubscription = async (id) => {
  await fetch(`http://localhost:5000/subscriptions/${id}`, {
    method: "DELETE",
  });

  setSubscriptions(subscriptions.filter((sub) => sub.id !== id));
};

    const newSub = {
      id: Date.now(),
      name: trimmedName,
      amount: parsedAmount,
    };

    setSubscriptions([...subscriptions, newSub]);

    fetch("http://localhost:5000/subscriptions", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(newSub),
    }).catch((err) => console.error(err));

    setName("");   // Clear after adding
    setAmount(""); 
  };

  return (
    <div className="bg-white rounded-xl shadow p-6 mb-8">
      <h3 className="text-lg font-semibold mb-4">Add Subscription</h3>
<div className="grid grid-cols-3 gap-3">
  <input
    type="text"
    placeholder="Subscription Name"
    className="border p-2 rounded col-span-1"
    value={name}
    onChange={(e) => setName(e.target.value)}
  />

  <input
    type="number"
    placeholder="Amount"
    className="border p-2 rounded col-span-1"
    value={amount}
    onChange={(e) => setAmount(e.target.value)}
  />

  <button
    className="bg-green-500 text-white px-4 py-2 rounded col-span-1"
    onClick={addSubscription}
  >
    Add
  </button>
   <button
          className="bg-red-500 text-white px-2 py-1 rounded"
          onClick={() => deleteSubscription(sub.id)}
        >
          Delete
        </button>
</div>

      {subscriptions.length > 0 && (
        <ul className="mt-4 space-y-2">
          {subscriptions.map((sub) => (
            <li key={sub.id} className="flex justify-between text-gray-700">
              <span>{sub.name}</span>
              <span>₹{sub.amount ? Number(sub.amount).toFixed(2) : "0.00"}</span>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default SubscriptionForm;
